insight.code_example:
mutation {
  marketCreateShippingProfile(
    marketId: "market-id"
    profile: {
      name: "Shipping Profile"
      shippingRates: [
        {
          price: {
            amount: 10.0
            currencyCode: USD
          }
          weightRange: {
            maximum: 10.0
            minimum: 0.0
          }
        }
      ]
    }
  ) {
    market {
      id
    }
    profile {
      id
    }
    userErrors {
      field
      message
    }
  }
}
